+    let mut had_namespace = false;
+    while let Some(rest) = suffix.strip_prefix(FIELD_NAMESPACE_PREFIX) {
+        suffix = rest;
+        had_namespace = true;
+    }
+
+    had_namespace && RESERVED_JSON_FIELDS.contains(&suffix)
+}
